INSERT INTO "codes" ("id","code","normalized_code","title","category","status","source","note","added_at","updated_at") VALUES(294,'8491DA','8491DA','saikai','其他 ACG 音乐','ok','自己',replace('致：读出：痛苦啊，你就是我的唯一。\n\n除了你，我皆无欲求。 痛苦啊，你忠实地陪伴着我，直至现在也没有一丝改变。 当我的灵魂徘徊于深渊之底时。 唯有你相伴在我的身旁，守护着我。 我又怎能埋怨你呢。 痛苦啊，你绝不会从我的身旁遁走。 我终于能够表达对你的尊敬。 现在也认识到了你的存在。 而你只是存在于世，就已那么美丽。 痛苦啊，你就像那从未离开我那贫苦的心之火炉旁的人一样。 比我那身为至爱的恋人还要多情。 我知道在我迈向死亡的那一天。 你会进到我的内心深处。 与我并排躺下。','\n',char(10)),'2026-07-16T03:44:16.312Z','2026-07-16 17:23:15');
